import os, glob, base64, json, subprocess; from config import URL_WEB_APP; FOLDER_SCREENSHOT = '/sdcard/DCIM/Screenshots/*'; list_files = glob.glob(FOLDER_SCREENSHOT); (exit()) if not list_files else None; ss_terbaru = max(list_files, key=os.path.getctime); nama_file = os.path.basename(ss_terbaru); file_log = 'terakhir_dikirim.txt'; last_sent = open(file_log, 'r').read().strip() if os.path.exists(file_log) else ''; (exit()) if nama_file == last_sent else None; print(f'📸 Menemukan SS Baru: {nama_file}'); img = open(ss_terbaru, 'rb'); encoded = base64.b64encode(img.read()).decode('utf-8'); img.close(); payload = json.dumps({'image': encoded, 'filename': nama_file}); f = open('payload_temp.json', 'w', encoding='utf-8'); f.write(payload); f.close(); print('🚀 Mengirim otomatis ke Cloud...'); cmd = ['curl', '-s', '-X', 'POST', '-H', 'Content-Type: application/json', '-d', '@payload_temp.json', URL_WEB_APP]; subprocess.run(cmd, stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL); open(file_log, 'w').write(nama_file); os.remove('payload_temp.json') if os.path.exists('payload_temp.json') else None; print('✅ Sukses Terkirim')
